@@ -0,0 +1,854 @@
+//! Mock transport implementations for testing.
+//!
+//! These mocks implement `SymbolSink` and `SymbolStream` with deterministic,
+//! configurable behaviors for testing transport behavior without real I/O.
+
+use crate::security::authenticated::AuthenticatedSymbol;
+use crate::transport::error::{SinkError, StreamError};
+use crate::transport::{SymbolSink, SymbolStream};
+use crate::types::Symbol;
+use crate::util::DetRng;
+use std::collections::{HashMap, HashSet, VecDeque};
+use std::pin::Pin;
+use std::sync::{Arc, Mutex};
+use std::task::{Context, Poll, Waker};
+use std::time::{Duration, Instant};
+
+/// Configuration for mock transport behavior.
+#[derive(Debug, Clone)]
+pub struct MockTransportConfig {
+    /// Base latency added to every operation.
+    pub base_latency: Duration,
+    /// Random latency jitter (uniform distribution 0..jitter).
+    pub latency_jitter: Duration,
+    /// Probability (0.0-1.0) of symbol loss.
+    pub loss_rate: f64,
+    /// Probability (0.0-1.0) of symbol duplication.
+    pub duplication_rate: f64,
+    /// Probability (0.0-1.0) of symbol corruption.
+    pub corruption_rate: f64,
+    /// Maximum symbols in flight before backpressure.
+    pub capacity: usize,
+    /// Seed for deterministic random behavior (None uses a deterministic seed).
+    pub seed: Option<u64>,
+    /// Whether to preserve symbol ordering.
+    pub preserve_order: bool,
+    /// Error injection: fail after N successful operations.
+    pub fail_after: Option<usize>,
+}
+
+impl Default for MockTransportConfig {
+    fn default() -> Self {
+        Self {
+            base_latency: Duration::ZERO,
+            latency_jitter: Duration::ZERO,
+            loss_rate: 0.0,
+            duplication_rate: 0.0,
+            corruption_rate: 0.0,
+            capacity: 1024,
+            seed: None,
+            preserve_order: true,
+            fail_after: None,
+        }
+    }
+}
+
+impl MockTransportConfig {
+    /// Create config for reliable, zero-latency transport (unit tests).
+    #[must_use]
+    pub fn reliable() -> Self {
+        Self::default()
+    }
+
+    /// Create config simulating a lossy network.
+    #[must_use]
+    pub fn lossy(loss_rate: f64) -> Self {
+        Self {
+            loss_rate,
+            ..Self::default()
+        }
+    }
+
+    /// Create config simulating network latency.
+    #[must_use]
+    pub fn with_latency(base: Duration, jitter: Duration) -> Self {
+        Self {
+            base_latency: base,
+            latency_jitter: jitter,
+            ..Self::default()
+        }
+    }
+
+    /// Create deterministic config for reproducible tests.
+    #[must_use]
+    pub fn deterministic(seed: u64) -> Self {
+        Self {
+            seed: Some(seed),
+            ..Self::default()
+        }
+    }
+}
+
+/// Node identifier for mock network topologies.
+pub type NodeId = u64;
+
+/// Mock link configuration between two nodes.
+#[derive(Debug, Clone)]
+pub struct MockLink {
+    /// Transport behavior for this link.
+    pub config: MockTransportConfig,
+}
+
+/// Simulated network topology for mock transports.
+#[derive(Debug)]
+pub struct MockNetwork {
+    nodes: HashSet<NodeId>,
+    links: HashMap<(NodeId, NodeId), MockLink>,
+    default_config: MockTransportConfig,
+}
+
+impl MockNetwork {
+    /// Create a fully-connected network of N nodes.
+    #[must_use]
+    pub fn fully_connected(n: usize, config: MockTransportConfig) -> Self {
+        let mut nodes = HashSet::new();
+        let mut links = HashMap::new();
+        for i in 0..n {
+            nodes.insert(i as NodeId);
+        }
+        for &from in &nodes {
+            for &to in &nodes {
+                if from != to {
+                    links.insert((from, to), MockLink {
+                        config: config.clone(),
+                    });
+                }
+            }
+        }
+        Self {
+            nodes,
+            links,
+            default_config: config,
+        }
+    }
+
+    /// Create a ring topology.
+    #[must_use]
+    pub fn ring(n: usize, config: MockTransportConfig) -> Self {
+        let mut nodes = HashSet::new();
+        let mut links = HashMap::new();
+        if n == 0 {
+            return Self {
+                nodes,
+                links,
+                default_config: config,
+            };
+        }
+        for i in 0..n {
+            nodes.insert(i as NodeId);
+        }
+        for i in 0..n {
+            let from = i as NodeId;
+            let to = ((i + 1) % n) as NodeId;
+            links.insert((from, to), MockLink {
+                config: config.clone(),
+            });
+            links.insert((to, from), MockLink {
+                config: config.clone(),
+            });
+        }
+        Self {
+            nodes,
+            links,
+            default_config: config,
+        }
+    }
+
+    /// Partition the network (some nodes can't reach others).
+    pub fn partition(&mut self, group_a: &[NodeId], group_b: &[NodeId]) {
+        for &a in group_a {
+            for &b in group_b {
+                self.links.remove(&(a, b));
+                self.links.remove(&(b, a));
+            }
+        }
+    }
+
+    /// Heal a partition by restoring links with the default config.
+    pub fn heal_partition(&mut self, group_a: &[NodeId], group_b: &[NodeId]) {
+        for &a in group_a {
+            for &b in group_b {
+                if a == b {
+                    continue;
+                }
+                if self.nodes.contains(&a) && self.nodes.contains(&b) {
+                    self.links.insert((a, b), MockLink {
+                        config: self.default_config.clone(),
+                    });
+                    self.links.insert((b, a), MockLink {
+                        config: self.default_config.clone(),
+                    });
+                }
+            }
+        }
+    }
+
+    /// Get a transport pair for communication between two nodes.
+    ///
+    /// If the link is missing, returns a closed channel pair.
+    #[must_use]
+    pub fn transport(&self, from: NodeId, to: NodeId) -> (MockChannelSink, MockChannelStream) {
+        if let Some(link) = self.links.get(&(from, to)) {
+            mock_channel(link.config.clone())
+        } else {
+            closed_channel(self.default_config.clone())
+        }
+    }
+}
+
+#[derive(Debug)]
+struct DelayState {
+    waker: Option<Waker>,
+    spawned: bool,
+}
+
+#[derive(Debug)]
+struct Delay {
+    deadline: Instant,
+    state: Arc<Mutex<DelayState>>,
+}
+
+impl Delay {
+    fn new(duration: Duration) -> Self {
+        let now = Instant::now();
+        let deadline = now.checked_add(duration).unwrap_or(now);
+        Self {
+            deadline,
+            state: Arc::new(Mutex::new(DelayState {
+                waker: None,
+                spawned: false,
+            })),
+        }
+    }
+
+    fn poll(&self, cx: &Context<'_>) -> Poll<()> {
+        if Instant::now() >= self.deadline {
+            return Poll::Ready(());
+        }
+
+        let mut state = self.state.lock().expect("mock delay lock poisoned");
+        state.waker = Some(cx.waker().clone());
+
+        if !state.spawned {
+            state.spawned = true;
+            let deadline = self.deadline;
+            let state_clone = Arc::clone(&self.state);
+            drop(state);
+            std::thread::spawn(move || {
+                let now = Instant::now();
+                if deadline > now {
+                    std::thread::sleep(deadline - now);
+                }
+                let mut state = state_clone.lock().expect("mock delay lock poisoned");
+                if let Some(waker) = state.waker.take() {
+                    waker.wake();
+                }
+                state.spawned = false;
+            });
