+        state.closed = true;
+        let send_wakers = std::mem::take(&mut state.send_wakers);
+        let recv_wakers = std::mem::take(&mut state.recv_wakers);
+        drop(state);
+        for waker in send_wakers {
+            waker.wake();
+        }
+        for waker in recv_wakers {
+            waker.wake();
+        }
+    }
